# FINAL_OG_REBUILD_FLAT_CSV_PUBLIC.ps1
# One final rebuild from the original Downloads folder.
#
# Fixes included:
# - Uses OG folder as source of truth.
# - Backs up current public tree before regenerating.
# - Preserves full OG folder under archive/.
# - Public folders use CSV, Markdown, JPG, and PDF.
# - No public XLSX spreadsheet files.
# - No extra *_csv folders.
# - Drain/result CSVs go under validation, not hardware/bom.
# - Isolation Transformer becomes first-class under tools/isolation-transformer.
# - Middlebrook Injector remains first-class under tools/middlebrook-injector.
# - HEIC images are converted to JPG using ImageMagick.
# - DOCX build guides/notes are extracted to Markdown.
#
# Run:
# powershell -ExecutionPolicy Bypass -File .\FINAL_OG_REBUILD_FLAT_CSV_PUBLIC.ps1

$ErrorActionPreference = "Stop"

function Get-PythonCommand {
    $py = Get-Command py -ErrorAction SilentlyContinue
    if ($null -ne $py) { return "py" }
    $python = Get-Command python -ErrorAction SilentlyContinue
    if ($null -ne $python) { return "python" }
    return $null
}

$PythonCmd = Get-PythonCommand
if ($null -eq $PythonCmd) {
    Write-Host "ERROR: Python not found as py or python." -ForegroundColor Red
    exit 1
}

$RepoRoot = "C:\Git\5V-1A SMPS"
if (-not (Test-Path -LiteralPath $RepoRoot)) {
    New-Item -ItemType Directory -Path $RepoRoot | Out-Null
}

$HelperPath = Join-Path $RepoRoot "FINAL_OG_REBUILD_FLAT_CSV_PUBLIC_HELPER.py"
$B64 = ""
[System.IO.File]::WriteAllBytes($HelperPath, [System.Convert]::FromBase64String($B64))

Write-Host "Running final OG rebuild with flat CSV public artifacts..." -ForegroundColor Cyan
& $PythonCmd $HelperPath

if ($LASTEXITCODE -ne 0) {
    Write-Host "Failed with exit code $LASTEXITCODE" -ForegroundColor Red
    exit $LASTEXITCODE
}

Write-Host ""
Write-Host "Done. Commit with:" -ForegroundColor Green
Write-Host 'cd "C:\Git\5V-1A SMPS"'
Write-Host "git status --untracked-files=all"
Write-Host "git add README.md .gitignore .gitattributes LICENSE docs hardware validation tools archive"
Write-Host 'git commit -m "Final rebuild from original folder with flat CSV artifacts"'
Write-Host "git push"
